class FilemakerRecord{constructor(){this.fields={};this.portalData=[];this.recordId="0";this.modId="0"}setField(name,value){this.fields[name]=value}getField(name){return this.fields[name]}static fromJSON(json){let record=new FilemakerRecord;if(json===[]||json.fieldData===undefined||json.portalData===undefined||json.recordId===undefined||json.modId===undefined){return record}record.fields=json.fieldData;record.portalData=json.portalData;record.recordId=json.recordId;record.modId=json.modId;return record}}class Filemaker{constructor(url,username="",password="",database="",layout=""){this.url=url;this.username=username;this.password=password;this.database=database;this.layout=layout;process.env.NODE_TLS_REJECT_UNAUTHORIZED="0"}withUrl(url){this.url=url;return this}withUsername(username){this.username=username;return this}withPassword(password){this.password=password;return this}withDatabase(database){this.database=database;return this}withLayout(layout){this.layout=layout;return this}async getActiveSessions(){const headers=new Headers;headers.set("Accept","application/json");try{const response=await fetch(`${this.url}/auth/active`,{headers:headers});return await response.json()}catch(e){console.error(e)}throw new Error("Failed to fetch active users")}async search(query){if(this.username===""&&this.password===""&&this.database===""&&this.layout===""){throw new Error("Required fields are not set. Please set the username, password, database, and layout before making a request.")}const headers=new Headers;headers.set("Accept","application/json");headers.set("X-Authentication-Options",JSON.stringify({username:this.username,password:this.password}));try{const response=await fetch(`${this.url}/databases/${this.database}/layouts/${this.layout}/search?query=${encodeURIComponent(query)}`,{headers:headers});let json=await response.json();let records=[];for(let record of json){records.push(FilemakerRecord.fromJSON(record))}return records}catch(e){console.error(e);throw new Error("Failed to search for records")}}async advancedSearch(fields,sort=[],ascending=false){if(this.username===""&&this.password===""&&this.database===""&&this.layout===""){throw new Error("Required fields are not set. Please set the username, password, database, and layout before making a request.")}try{const myHeaders=new Headers;myHeaders.append("X-Authentication-Options",`{"username": "${this.username}",    "password": "${this.password}" }`);myHeaders.append("Accept","application/json");myHeaders.append("Content-Type","application/json");const raw=JSON.stringify({fields:fields,sort:sort,ascending:ascending});const requestOptions={method:"POST",headers:myHeaders,body:raw,redirect:"follow"};const response=await fetch(`${this.url}/databases/${this.database}/layouts/${this.layout}/search`,requestOptions);const json=await response.json();return json.map(record=>FilemakerRecord.fromJSON(record))}catch(e){console.error(e);throw new Error("Failed to search for records")}}async getDatabases(){if(this.username===""&&this.password===""){throw new Error("Required fields are not set. Please set the username and password before making a request.")}const headers=new Headers;headers.set("Accept","application/json");headers.set("X-Authentication-Options",JSON.stringify({username:this.username,password:this.password}));try{const response=await fetch(`${this.url}/databases`,{headers:headers});return Array.from(await response.json())}catch(e){console.error(e);throw new Error("Failed to fetch databases")}}async getLayouts(){if(this.username===""&&this.password===""&&this.database===""){throw new Error("Required fields are not set. Please set the username, password and database before making a request.")}const headers=new Headers;headers.set("Accept","application/json");headers.set("X-Authentication-Options",JSON.stringify({username:this.username,password:this.password}));try{const response=await fetch(`${this.url}/databases/${this.database}/layouts`,{headers:headers});return Array.from(await response.json())}catch(e){console.error(e);throw new Error("Failed to fetch layouts")}}async getRecords(limit=10,offset=0){if(this.username===""&&this.password===""&&this.database===""&&this.layout===""){throw new Error("Required fields are not set. Please set the username, password, database, and layout before making a request.")}const headers=new Headers;headers.set("Accept","application/json");headers.set("X-Authentication-Options",JSON.stringify({username:this.username,password:this.password}));try{process.env.NODE_TLS_REJECT_UNAUTHORIZED="0";const response=await fetch(`${this.url}/databases/${this.database}/layouts/${this.layout}/records?limit=${limit}&offset=${offset}`,{headers:headers});let json=await response.json();let records=[];for(let record of json){records.push(FilemakerRecord.fromJSON(record))}return records}catch(e){console.error(e);throw new Error("Failed to fetch records")}}async getRecord(id){if(this.username===""&&this.password===""&&this.database===""&&this.layout===""){throw new Error("Required fields are not set. Please set the username, password, database, and layout before making a request.")}const headers=new Headers;headers.set("Accept","application/json");headers.set("X-Authentication-Options",JSON.stringify({username:this.username,password:this.password}));try{process.env.NODE_TLS_REJECT_UNAUTHORIZED="0";const response=await fetch(`${this.url}/databases/${this.database}/layouts/${this.layout}/records/${id}`,{headers:headers});let json=await response.json();return FilemakerRecord.fromJSON(json)}catch(e){console.error(e);throw new Error("Failed to fetch records")}}async getRecordCount(){if(this.username===""&&this.password===""&&this.database===""&&this.layout===""){throw new Error("Required fields are not set. Please set the username, password, database, and layout before making a request.")}const headers=new Headers;headers.set("Accept","application/json");headers.set("X-Authentication-Options",JSON.stringify({username:this.username,password:this.password}));try{process.env.NODE_TLS_REJECT_UNAUTHORIZED="0";const response=await fetch(`${this.url}/databases/${this.database}/layouts/${this.layout}/records/count`,{headers:headers});let json=await response.json();return json.count}catch(e){console.error(e);throw new Error("Failed to fetch records")}finally{process.env.NODE_TLS_REJECT_UNAUTHORIZED="1"}}async getRows(){if(this.username===""&&this.password===""&&this.database===""&&this.layout===""){throw new Error("Required fields are not set. Please set the username, password, database, and layout before making a request.")}const headers=new Headers;headers.set("Accept","application/json");headers.set("X-Authentication-Options",JSON.stringify({username:this.username,password:this.password}));try{process.env.NODE_TLS_REJECT_UNAUTHORIZED="0";const response=await fetch(`${this.url}/databases/${this.database}/layouts/${this.layout}/fields`,{headers:headers});let json=await response.json();return Array.from(json)}catch(e){console.error(e);throw new Error("Failed to fetch records")}}async updateRecord(id,record,addIfMissing=false){if(this.username===""&&this.password===""&&this.database===""&&this.layout===""){throw new Error("Required fields are not set. Please set the username, password, database, and layout before making a request.")}const headers=new Headers;headers.set("Accept","application/json");headers.set("Content-Type","application/json");headers.set("X-Authentication-Options",JSON.stringify({username:this.username,password:this.password}));try{process.env.NODE_TLS_REJECT_UNAUTHORIZED="0";const response=await fetch(`${this.url}/databases/${this.database}/layouts/${this.layout}/records/${id}?force-add=${addIfMissing}`,{method:"POST",headers:headers,body:JSON.stringify(record["fields"])});let json=await response.json();return FilemakerRecord.fromJSON(json)}catch(e){console.error(e);throw new Error("Failed to update record")}}async deleteRecord(id){if(this.username===""&&this.password===""&&this.database===""&&this.layout===""){throw new Error("Required fields are not set. Please set the username, password, database, and layout before making a request.")}const headers=new Headers;headers.set("Accept","application/json");headers.set("X-Authentication-Options",JSON.stringify({username:this.username,password:this.password}));try{process.env.NODE_TLS_REJECT_UNAUTHORIZED="0";await fetch(`${this.url}/databases/${this.database}/layouts/${this.layout}/records/${id}`,{method:"DELETE",headers:headers})}catch(e){console.error(e);throw new Error("Failed to delete record")}}async deleteAllRecords(){if(this.username===""&&this.password===""&&this.database===""&&this.layout===""){throw new Error("Required fields are not set. Please set the username, password, database, and layout before making a request.")}const headers=new Headers;headers.set("Accept","application/json");headers.set("X-Authentication-Options",JSON.stringify({username:this.username,password:this.password}));try{process.env.NODE_TLS_REJECT_UNAUTHORIZED="0";await fetch(`${this.url}/databases/${this.database}/layouts/${this.layout}/records`,{method:"DELETE",headers:headers})}catch(e){console.error(e);throw new Error("Failed to delete records")}}async addRecord(record){if(this.username===""&&this.password===""&&this.database===""&&this.layout===""){throw new Error("Required fields are not set. Please set the username, password, database, and layout before making a request.")}const headers=new Headers;headers.set("Accept","application/json");headers.set("Content-Type","application/json");headers.set("X-Authentication-Options",JSON.stringify({username:this.username,password:this.password}));try{process.env.NODE_TLS_REJECT_UNAUTHORIZED="0";const response=await fetch(`${this.url}/databases/${this.database}/layouts/${this.layout}/records`,{method:"POST",headers:headers,body:JSON.stringify(record["fields"])});let json=await response.json();return FilemakerRecord.fromJSON(json)}catch(e){console.error(e,record);throw new Error("Failed to add record")}}async validateCredentials(username,password,database){if(username===""||password===""||database==="")throw new Error("Username, password, and database are required fields");const body=JSON.stringify({username:username,password:password,database:database});try{process.env.NODE_TLS_REJECT_UNAUTHORIZED="0";const response=await fetch(`${this.url}/credentials`,{method:"POST",body:body,headers:{"Content-Type":"application/json",accept:"application/json"}});if(response.ok){this.username=username;this.password=password;this.database=database;return{success:true,message:"Credentials are valid"}}else{return{success:false,message:"Invalid credentials"}}}catch(e){console.error(e);return{message:e,success:false}}}static buildTable(items,ignoredFields=[]){const table=document.createElement("table");const head=document.createElement("thead");const body=document.createElement("tbody");const rowNames=Object.keys(items[0].fields);const header=document.createElement("tr");for(const row of rowNames){if(ignoredFields.includes(row))continue;const th=document.createElement("th");th.textContent=row;header.appendChild(th)}head.appendChild(header);table.appendChild(head);for(const record of items){const tr=document.createElement("tr");for(const row of rowNames){if(ignoredFields.includes(row))continue;const td=document.createElement("td");td.textContent=record.fields[row];tr.appendChild(td)}body.appendChild(tr)}table.appendChild(body);return table}}module.exports={Filemaker:Filemaker,FilemakerRecord:FilemakerRecord};